use bazi;

INSERT INTO `tb_bazi_interpretation`
(`god_type`, `ganzhi_position`, `basic_def`, `main_content`, `support_content`, `restrict_content`, `gender_diff`, `tag`, `help_count`, `unhelp_count`, `comment_count`)
VALUES
    ('正财', '年干',
     '正财为日干所克、与日干阴阳不同，代表稳定财物、正业收入、务实本分、物质积累，是八字中代表正当财运、踏实求财、衣食无忧的星神，正财得位者，为人勤俭务实、脚踏实地、重视物质安稳；年干为八字的门户，代表祖辈福泽、外在形象、年少运势、他人对你的第一印象，年干坐正财，意味着你的外在形象、年少成长、祖辈家境、他人初印象，都与务实、安稳、求财有道深度绑定，主年少家境尚可，早年便有理财意识，需学会守财聚福、稳步积累。',
     '【性格】外在形象给人的第一印象是「踏实稳重、勤俭务实、靠谱本分」，为人处事脚踏实地，不喜投机取巧，做任何事都讲究循序渐进、有理有据，凡事都会提前规划，极少做无准备的事；性格内敛沉稳，不善言辞但内心通透，待人真诚厚道，重情重义且懂得感恩，身边的人都愿意信任你、托付你；生活中极度勤俭节约，对钱财有规划、不铺张浪费，能把收入合理分配，擅长积少成多，但短板也很明显，性格偏保守固执，缺乏变通思维，对新鲜事物接受度低，容易因过度谨慎而错失良机，也容易因看重物质而显得格局偏小。
     【情感】对伴侣的核心诉求是「踏实本分、勤俭顾家、三观相合」，极度反感好高骛远、好吃懒做、花钱大手大脚的人，更倾向于选择性格稳重、有稳定收入、懂得珍惜生活的伴侣；感情中你是极致专一且负责任的人，一旦认定便会用心经营，愿意为对方付出所有，会把伴侣的安稳放在第一位，相处中虽少了浪漫惊喜，但多了踏实陪伴，能给对方十足的安全感；感情里的短板是不懂制造情趣，表达爱意的方式过于朴实，容易让对方觉得平淡无味，也容易因过度看重物质条件，忽略了情感的核心需求。
     【职业】天生适配「需要踏实本分、稳步积累、注重规则」的岗位，事业发展的核心基调是「稳中求进、靠实干取胜」，靠脚踏实地的付出获得稳定回报，不适合高风险、高波动的行业；适配的职业包括财务会计、行政文员、国企职员、教师、制造业技术岗、传统行业销售，这类工作能发挥你的务实优势，收入稳定且晋升路径清晰，只要坚持深耕，便能积累可观的财富与资历；不适合创业、投机类、新媒体等需要灵活变通、敢闯敢拼的岗位，容易因保守性格而错失风口，也难以适应快速变化的行业节奏。',
     '正财得五行生扶，代表财星得力、福禄深厚，务实转化为优势，安稳带来长久福报：性格上，稳重转化为可靠，务实转化为智慧，既能坚守本心稳步前行，也能适度变通把握机遇，待人处事方圆有度，口碑极佳；事业上，年少便有贵人相助，祖辈能给予一定的物质支持，职场中稳步晋升，正业收入持续增长，理财有道且能守财聚福，财富积累越来越丰厚；情感上，能遇到门当户对、踏实顾家的优质伴侣，彼此三观相合、勤俭持家，婚姻生活安稳幸福、衣食无忧；生活中，凡事顺心如意，少有波折，一生安稳顺遂。',
     '正财被五行克泄，代表财星受制、财运受阻，保守变成短板，务实变成固执：性格上，勤俭变成吝啬，务实变成死板，遇事墨守成规、不懂变通，对钱财过度执着，甚至会为了利益斤斤计较，身边的人逐渐疏远，人脉越来越单薄；事业上，年少家境普通，祖辈无助力，职场中付出多收获少，正业收入微薄，求财之路坎坷不顺，即便有机会也会因过度谨慎而错失，理财也容易出现亏损，钱财留不住；情感上，容易遇到「好高骛远、好吃懒做」的伴侣，彼此三观不合，频繁因钱财、生活理念争吵，感情难以长久；生活中，琐事缠身、压力重重，凡事都需亲力亲为，难得安稳。',
     '男性：事业上是典型的「实干家」，靠踏实付出积累财富，但容易因过度保守而错失赚钱良机，需学会适度变通、大胆尝试；感情中是绝佳的丈夫，顾家负责、踏实可靠，但缺乏浪漫细胞，需学会制造惊喜、表达爱意，方能让婚姻更甜蜜。
     女性：正财为女命的「福财星」，年干坐正财代表年少有福，易得祖辈疼爱与物质支持；感情中择偶标准务实，能嫁得安稳本分的伴侣，但需注意不要因过度看重对方的经济条件，而忽略了彼此的情感共鸣。',
     '财运;务实;祖辈;安稳', 0, 0, 0);

INSERT INTO `tb_bazi_interpretation`
(`god_type`, `ganzhi_position`, `basic_def`, `main_content`, `support_content`, `restrict_content`, `gender_diff`, `tag`, `help_count`, `unhelp_count`, `comment_count`)
VALUES
    ('正财', '年支',
     '正财为日干所克、与日干阴阳不同，代表稳定财物、正业收入、务实本分、物质积累，是八字中代表正当财运、踏实求财、衣食无忧的星神，正财得位者，为人勤俭务实、脚踏实地、重视物质安稳；年支为八字的根基，代表祖辈家业、家庭环境、童年成长、宗族助力，年支坐正财，意味着你的家庭根基、童年生活、祖辈助力，都与物质安稳、家业丰厚深度绑定，主祖辈家境殷实，家庭氛围和睦，童年衣食无忧，需学会珍惜福报、守业兴业。',
     '【性格】性格里刻着「踏实本分、温和厚道、知足常乐」的特质，从小在安稳的家庭环境中长大，内心充满安全感，待人处事谦和有礼，懂得换位思考、体谅他人，极少与人争执；为人勤俭持家，对生活有规划，不喜铺张浪费，能把日子过得井井有条，做事认真负责、任劳任怨，无论对家庭还是工作，都能尽心尽力做到最好；但性格偏慢热内敛，缺乏冒险精神，对未知的事物充满顾虑，容易安于现状、不思进取，也容易因过度依赖家庭，缺乏独立打拼的勇气。
     【情感】对伴侣的核心诉求是「安稳顾家、温和厚道、懂得珍惜」，极度反感性格暴躁、好高骛远、不顾家的人，更倾向于选择成长环境相似、三观相合、能一起安稳过日子的伴侣；感情中你是温柔体贴的人，懂得包容对方的缺点，愿意为家庭付出，相处中虽少了轰轰烈烈的激情，但多了细水长流的温暖，能把感情经营得安稳长久；感情里的短板是过于依赖对方的陪伴，缺乏独立的情感空间，也容易因过度迁就对方，失去自己的原则与底线。
     【职业】天生适配「安稳稳定、注重资历、无需奔波」的岗位，事业发展的核心基调是「背靠家庭、稳步前行」，祖辈或家人能给予一定的事业助力，无需独自打拼便能获得安稳的生活；适配的职业包括家族企业接班、国企职员、事业单位、教师、医护人员，这类工作能匹配你的安稳需求，收入稳定且福利完善，能让你在舒适的环境中发挥价值；不适合需要常年出差、高压竞争、风险较高的岗位，容易因适应不了节奏而身心俱疲，也难以发挥自身优势。',
     '正财得五行生扶，代表财星扎根、家业兴旺，家庭助力转化为事业优势：性格上，温和厚道变成人脉优势，身边的亲友都是贵人，遇事总能得到家人的支持与帮助，内心充满底气；事业上，祖辈家业丰厚，能给予实质性的物质或资源支持，职场中顺风顺水，正业收入稳定增长，还能依托家庭资源开展副业，财富积累事半功倍；情感上，能遇到家境相当、性格温和的伴侣，双方家庭和睦相处，婚姻生活幸福美满、衣食无忧；生活中，一生安稳顺遂，少有大起大落，福报深厚。',
     '正财被五行克泄，代表财星无根、家业薄弱，家庭助力变成拖累：性格上，温和变成懦弱，务实变成懒散，遇事缺乏主见、容易依赖他人，做事情半途而废、缺乏毅力，对生活没有规划，得过且过；事业上，祖辈家境普通，不仅无助力反而需要你分担家庭压力，职场中付出多收获少，正业收入微薄，求财之路举步维艰，即便有机会也难以把握；情感上，容易遇到「家境普通、缺乏担当」的伴侣，彼此为了生活琐事奔波，频繁因钱财争吵，感情在贫贱中逐渐消磨；生活中，琐事缠身、压力巨大，凡事都需独自承担，难得安稳。',
     '男性：事业上易得家人助力，能少走很多弯路，但需学会独立打拼，不要过度依赖家庭，方能成就自己的事业；感情中是顾家的好丈夫，能给予伴侣十足的安全感，但需学会保持独立的人格，不要过度迁就对方。
     女性：年支坐正财代表家庭根基稳固，一生衣食无忧，婚后能得到婆家的善待；感情中择偶注重安稳，能嫁得良人，但需注意不要因过度依赖家庭，失去自己的事业与追求。',
     '家境;祖辈;财运;安稳', 0, 0, 0);

INSERT INTO `tb_bazi_interpretation`
(`god_type`, `ganzhi_position`, `basic_def`, `main_content`, `support_content`, `restrict_content`, `gender_diff`, `tag`, `help_count`, `unhelp_count`, `comment_count`)
VALUES
    ('正财', '月干',
     '正财为日干所克、与日干阴阳不同，代表稳定财物、正业收入、务实本分、物质积累，是八字中代表正当财运、踏实求财、衣食无忧的星神，正财得位者，为人勤俭务实、脚踏实地、重视物质安稳；月干为八字的提纲、同辈圈层，代表兄弟姊妹、同窗好友、职场同事、中年运势，月干坐正财，意味着你的同辈关系、职场人脉、中年发展，都与务实求财、合作共赢深度绑定，主中年财运顺遂，同辈相助良多，需学会与人合作、互惠互利。',
     '【性格】性格上「精明务实、处事圆滑、懂得分寸」，为人聪明伶俐，能精准把握事物的核心本质，做事情讲究效率与回报，不喜做无用功；待人处事谦和有礼，懂得换位思考，与同辈相处和睦融洽，能与朋友、同事互帮互助，人脉资源丰富；生活中勤俭持家，对钱财有清晰的规划，擅长开源节流，能把收入合理分配，物质生活安稳富足；但短板是性格偏功利，做事情容易以利益为出发点，缺乏人情味，也容易因过度看重物质，忽略了精神层面的满足，偶尔会显得斤斤计较。
     【情感】对伴侣的核心诉求是「务实上进、懂得分担、三观相合」，极度反感游手好闲、好吃懒做、自私自利的人，更倾向于选择有稳定工作、积极上进、能一起打拼的伴侣；感情中你是理性且负责任的人，懂得平衡感情与物质，不会因爱情冲昏头脑，也不会因物质忽略感情，相处中能与伴侣并肩前行、共同成长，一起为美好生活奋斗；感情里的短板是表达爱意的方式过于理性，缺乏浪漫与情趣，容易让对方觉得你不够用心，也容易因钱财问题与伴侣产生分歧。
     【职业】天生适配「需要合作共赢、务实打拼、稳步增收」的岗位，事业发展的核心基调是「中年发力、靠人脉赚钱」，同辈与同事能给予你诸多助力，靠合作与实干获得稳定的事业与财富；适配的职业包括销售、采购、商务合作、财务管理、职场中层管理，这类工作能发挥你的务实与沟通优势，通过与人合作实现共赢，收入稳步增长且晋升空间大；不适合单打独斗、创意类、高风险的岗位，容易因缺乏人脉支持而举步维艰，也难以发挥自身的合作优势。',
     '正财得五行生扶，代表财星得力、同辈相助，务实转化为事业红利：性格上，精明务实变成处事智慧，既能坚守本心求财有道，也能懂得人情世故，待人处事方圆有度，人脉资源越来越广；事业上，中年运势大好，同辈与同事鼎力相助，职场中晋升顺利，正业收入持续增长，还能通过合作获得额外收益，财富积累越来越丰厚；情感上，能遇到积极上进、三观相合的伴侣，彼此并肩前行、共同打拼，婚姻生活安稳幸福、蒸蒸日上；生活中，凡事顺心如意，中年后家业兴旺、衣食无忧。',
     '正财被五行克泄，代表财星受制、同辈相争，务实变成功利，合作变成内耗：性格上，精明变成算计，务实变成小气，做事情斤斤计较、唯利是图，与同辈相处时容易因利益冲突产生矛盾，人脉资源逐渐流失；事业上，中年财运坎坷，同辈与同事不仅无助力反而处处争抢资源，职场中晋升受阻，正业收入微薄，求财之路举步维艰，即便有合作机会也容易被算计，得不偿失；情感上，容易遇到「自私自利、好吃懒做」的伴侣，彼此为了钱财争吵不休，感情在利益纠葛中逐渐消磨；生活中，中年压力巨大，琐事缠身，难得安稳。',
     '男性：事业上中年运势大好，易得同辈相助，能在合作中获得成功，但需学会坦诚待人，不要过于功利，方能长久发展；感情中是理性的伴侣，能给予对方稳定的物质生活，但需学会制造浪漫、表达爱意，方能让感情更长久。
     女性：月干坐正财代表中年财运顺遂，事业上能独当一面，经济独立且人格独立；感情中择偶注重上进，能嫁得积极肯干的伴侣，但需注意不要因过度看重物质，忽略了情感的温度。',
     '同辈;职场;财运;合作', 0, 0, 0);

